VALUES
  ('fire-eq-eng-moex-00863', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，建築物設置避難器具時，開口部與地面之間必須保有必要 之下降空間，下列敘述何者有誤？', '["設置避難梯時，二側豎桿中心線向外十五公分以上及其前方五十公分以上之範圍內", "設置直降式救助袋時，外牆如無突出物，救助袋與牆壁之間隔為三十公分以上。以救助袋為中心，半 徑一公尺圓柱形範圍內", "設置滑臺時，滑面上方一公尺以上及滑臺兩端向外二十公分以上所圍範圍內", "設置避難橋時，為橋之寬度以上及橋面上方二公尺以上所圍範圍內"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00864', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據可燃性高壓氣體儲存場所防爆牆設置基準，下列規定何者錯誤？', '["防爆牆分為鋼筋混凝土製、混凝土空心磚製及鋼板製等三種", "基礎混凝土經過二十八日養生後之抗壓強度140 kgf/cm2以上", "鋼板製防爆牆之鋼板應施以防銹處理，將鋼板表面清掃，油漆防銹塗料二次後，作修整油漆", "混凝土空心磚製防爆牆基礎埋入深度應在 250 mm 以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00865', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準，設置光電式分離型探測器之規定，下列敘述何者有誤？', '["設在與探測器光軸平行牆壁距離六十公分以上之位置", "探測器之受光器及送光器，設在距其背部牆壁二公尺範圍內", "設在天花板等高度二十公尺以下之場所", "探測器之光軸高度，在天花板等高度百分之八十以上之位置"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00866', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備檢修及申報作業基準之規定，對於查驗緊急照明設備之判斷標準，下列之敘 述何者錯誤？', '["於地下建築物之地下通道，緊急照明燈在地面之水平面照度應達2勒克斯（lux）以上；其它場所應達 到1勒克斯（lux）以上", "緊急電源容量需能持續三十分鐘以上", "建築物總樓地板面積3000平方公尺以下者，檢查數量應在10個以上", "建築物總樓地板面積10000平方公尺以上者，檢查數量為20個再追加「每增加5000平方公尺、增加5 個」的個數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00867', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，火警受信總機、中繼器及偵煙式探測器，有設定蓄積時間時， 蓄積時間之合計，每一火警分區在X秒以下，使用其他探測器時，在Y秒以下，請問X與Y分別為何？', '["X=30秒，Y=30秒", "X=45秒，Y=20秒", "X=45秒，Y=30秒", "X=60秒，Y=20秒"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00868', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準之規定，裝置水霧滅火設備之室內停車空間，排水設備相關規定為 車輛停駐場所地面需施作X%以上之坡度，設高Y公分以上之地區境界堤，請問X與Y分別為何？', '["X=2%，Y=5公分", "X=3%，Y=5公分", "X=2%，Y=10公分", "X=3%，Y=10公分"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00869', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備檢修及申報作業基準之規定，對於查驗惰性氣體滅火設備之判斷標準，下列 之敘述何者錯誤？', '["滅火藥劑儲存容器放置場所之溫度應在40℃以下", "藥劑量之測定結果與重量表或原廠技術手冊規範相互核對，差值應在充填值10%以下", "每一防護區域或防護對象物之警報系統應正確動作，距警報裝置一公尺處之音量應在九十分貝以上", "遲延裝置之動作時限應在三十秒以上，且在設計時之設定值範圍內"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00870', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備檢修及申報作業基準之規定，對於查驗火警自動警報設備之判斷標準，下列 之敘述何者錯誤？', '["在熱水室、消毒室等水蒸氣會大量滯留之場所，可採用定溫型1種之感熱式探測器", "在停車場、車庫等具有大量排放廢氣滯留之場所，不適合採用定溫型感熱式探測器", "光電式局限型２種之探測器動作時間應在90秒以內", "差動式局限型２種之探測器動作時間應在30秒以內"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00871', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據防火牆及防火水幕設置基準之規定，防火水幕之防護高度在十公尺以下時，每公尺水幕長度放水量 應在每分鐘X公升以上；防護高度超過十公尺者，高度每增加一公尺，放水量每分鐘應增加Y公升。請 問X與Y分別為何？', '["X=120公升，Y=8公升", "X=100公升，Y=10公升", "X=90公升，Y=8公升", "X=80公升，Y=10公升"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00872', 'fire-eq-eng', 'fire-eq-eng-moex-102-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據消防幫浦加壓送水裝置等及配管摩擦損失計算基準，有關啟動用水壓開關裝置應符合之規定，下列 何者有誤？', '["在啟動用壓力槽上或其近傍應裝設壓力表、啟動用水壓開關及試驗幫浦啟動用之排水閥", "啟動用壓力槽容量應有100公升以上", "啟動用壓力槽之構造應符合危險性機械及設備安全檢查規則之規定", "啟動用壓力儲槽應使用口徑 15mm 以上配管，與幫浦出水側逆止閥之一次側配管連接"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:18+00:00", "source_pdf_sha1": "8aecb6ec0845", "answer_pdf_sha1": "755533a816ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "102070", "c": "901", "s": "0702", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "消防法規", "year": "102", "exam_name": "102年專技驗船師引水人、第一次食品技師考試消防設備人員地政士專責報關人員保險人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
